import { UMB_PROPERTY_DATASET_CONTEXT } from '@umbraco-cms/backoffice/property';
import { UmbLitElement } from '@umbraco-cms/backoffice/lit-element';
import { html, css } from 'lit';
import { customElement, state } from 'lit/decorators.js';

const elementName = 'umb-headless-preview-workspace-view';

@customElement(elementName)
export class HeadlessWorkspaceViewElement extends UmbLitElement {
  @state()
  private headlessPreviewEnabled = false;

  @state()
  private entityId: string | undefined;

  static styles = [
    css`
      uui-toggle {
        margin-top: var(--uui-size-space-3);
      }
    `,
  ];

  constructor() {
    super();

    this.consumeContext(UMB_PROPERTY_DATASET_CONTEXT, async (propertyDatasetContext) => {
      this.entityId = propertyDatasetContext?.getUnique() ?? undefined;

      if (this.entityId) {
        await this.loadInitialState();
      }
    });
  }

  private async loadInitialState() {
    try {
      const response = await fetch(`/api/v1/umbraco.community.headless.blockpreview?id=${this.entityId}`);

      if (response.ok) {
        const data = await response.json();
        this.headlessPreviewEnabled = !!data.enabled;
      } else {
        console.error('Failed to load preview state', response.statusText);
      }
    } catch (err) {
      console.error('Error while fetching preview state', err);
    }
  }

  private async togglePreviewEnabled(e: Event) {
    const target = e.target as HTMLInputElement;
    this.headlessPreviewEnabled = target.checked;

    try {
      const response = await fetch('/api/v1/umbraco.community.headless.blockpreview', {
        method: 'PUT',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          id: this.entityId,
          enabled: this.headlessPreviewEnabled,
        }),
      });

      if (!response.ok) {
        console.error('Failed to update preview toggle', response.statusText);
      }
    } catch (err) {
      console.error('Error while toggling headless preview', err);
    }
  }

  render() {
    return html`
      <uui-box headline="Headless Block Preview">
        <uui-label for="headless-preview-toggle">Enable Preview</uui-label>

        <uui-toggle
          id="headless-preview-toggle"
          label="Headless Block Preview"
          .checked=${this.headlessPreviewEnabled}
          @change=${this.togglePreviewEnabled}>
        </uui-toggle>
      </uui-box>
    `;
  }
}
